import React, { useEffect, useRef } from "react";
import colorWheel from "../assets/images/colorwheel.jpeg"; // Path to the color wheel image

const ColorPicker = ({ onColorChange }) => {
  const canvasRef = useRef(null);

  // Load the color wheel image onto the canvas
  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    const image = new Image();
    image.src = colorWheel;
    image.onload = () => {
      ctx.drawImage(image, 0, 0, canvas.width, canvas.height);
    };
  }, []);

  // Handle click events on the canvas to get the selected color
  const handleCanvasClick = (event) => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    const rect = canvas.getBoundingClientRect();

    // Get the clicked position on the canvas
    const x = event.clientX - rect.left;
    const y = event.clientY - rect.top;

    // Get the pixel data at the clicked position
    const pixel = ctx.getImageData(x, y, 1, 1).data;
    const [r, g, b] = pixel;

    // Convert the RGB color to HEX format
    const hexColor = `#${((1 << 24) + (r << 16) + (g << 8) + b)
      .toString(16)
      .slice(1)}`;

    // Pass the selected color to the parent component
    onColorChange(hexColor);
  };

  return (
    <canvas
      ref={canvasRef}
      width={694} // Width of the canvas
      height={439} // Height of the canvas
      className="color-picker" // CSS class for styling
      onClick={handleCanvasClick} // Event listener for clicks
    />
  );
};

export default ColorPicker;
